Verb Description Example <code>%v</code> Default format <code>fmt.Printf("%v", 42)</code> → <code>42</code> <code>%+v</code> Adds struct field names <code>fmt.Printf("%+v", p)</code> <code>%#v</code> Go syntax representation <code>fmt.Printf("%#v", []int{1,2})</code> <code>%T</code> Type of value <code>fmt.Printf("%T", 42)</code> → <code>int</code> <code>%%</code> Literal percent sign <code>fmt.Printf("%%")</code> → <code>%</code> <p>General Verbs in Action</p> general_verbs.go<pre><code>package main

import "fmt"

type Person struct {
    Name string
    Age  int
}

func main() {
    p := Person{"Bob", 25}
    fmt.Printf("%v\n", p)     // {Bob 25}
    fmt.Printf("%+v\n", p)    // {Name:Bob Age:25}
    fmt.Printf("%#v\n", p)    // main.Person{Name:"Bob", Age:25}
    fmt.Printf("%T\n", p)     // main.Person
}
</code></pre>
